import xml.etree.ElementTree as ET

def parse_xml_config(filename):
    tree = ET.parse(filename)
    root = tree.getroot()
    settings = {}
    for child in root:
        if child.tag == 'setting':
            name = child.attrib['name']
            value = child.text
            settings[name] = value
    return settings